import redis
from flask import Flask, request, jsonify
import shlex

app = Flask(__name__)

r = redis.Redis(host='localhost', port=6379, db=0, decode_responses=False)

@app.route('/redis/command', methods=['GET'])
def execute_redis_command():
    command_string = request.args.get('command')

    if not command_string:
        return jsonify({
            "status": "error",
            "message": "No 'command' parameter provided."
        }), 400

    try:
        command_parts = shlex.split(command_string)
        if not command_parts:
            return jsonify({
                "status": "error",
                "message": "Invalid empty command string."
            }), 400

        result = r.execute_command(*command_parts)

        if isinstance(result, bytes):
            result = result.decode('utf-8', errors='ignore')
        elif isinstance(result, list):
            result = [
                item.decode('utf-8', errors='ignore') if isinstance(item, bytes) else item
                for item in result
            ]

        return jsonify({
            "status": "success",
            "command": command_string,
            "result": result
        }), 200

    except redis.exceptions.RedisError as e:
        return jsonify({
            "status": "error",
            "command": command_string,
            "message": str(e)
        }), 400

    except Exception as e:
        return jsonify({
            "status": "error",
            "command": command_string,
            "message": f"An unexpected error occurred: {str(e)}"
        }), 500

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)